"""
Test mixin for json_path constraint tests.

Usage::

    class TestJsonPathXGrammar(TestJsonPathConstrainedMixin, unittest.TestCase):
        base_url = "http://localhost:30000"
"""

import json
import re

import requests


def _check_json_path(data: object, segments) -> bool:
    """
    Recursively verify that *data* satisfies the structural requirements of a
    pre-parsed list of path segments.

    Each segment is a ``(type, value)`` tuple as produced by the tokeniser in
    :mod:`sglang.srt.constrained.json_path_constraint`.
    """
    if not segments:
        # All segments consumed – the path exists in *data*
        return True

    seg_type, seg_value = segments[0]
    rest = segments[1:]

    if seg_type == "key":
        if not isinstance(data, dict):
            return False
        if seg_value not in data:
            return False
        return _check_json_path(data[seg_value], rest)

    if seg_type == "array":
        if not isinstance(data, list):
            return False
        if seg_value == "*":
            # Every element must satisfy the remainder of the path
            if not data:
                return False
            return all(_check_json_path(item, rest) for item in data)
        # Integer index
        idx = int(seg_value)
        if idx >= len(data):
            return False
        return _check_json_path(data[idx], rest)

    return False


def validate_json_path(text: str, path: str) -> bool:
    """
    Return ``True`` when *text* is valid JSON and the JSON value it contains
    satisfies the structural requirements implied by *path*.

    This helper is intentionally self-contained (no dependency on the
    ``json_path_constraint`` module) so that tests can run without importing
    the server-side code.

    Args:
        text: The generated text to validate.
        path: A JSONPath expression starting with ``$``.

    Returns:
        ``True`` if the text passes validation, ``False`` otherwise.
    """
    # Must parse as valid JSON
    try:
        data = json.loads(text)
    except (json.JSONDecodeError, ValueError):
        return False

    if not path.startswith("$"):
        return False

    # Tokenise the path locally (mirrors json_path_constraint._tokenize)
    segments = []
    pos = 1  # skip '$'
    while pos < len(path):
        ch = path[pos]
        if ch == ".":
            pos += 1
            if pos < len(path) and path[pos] != "[":
                m = re.match(r"([A-Za-z_$][A-Za-z0-9_$\-]*)", path[pos:])
                if m:
                    segments.append(("key", m.group(1)))
                    pos += len(m.group(1))
                    continue
        if pos < len(path) and path[pos] == "[":
            pos += 1  # skip '['
            if pos < len(path) and path[pos] == "*":
                pos += 2  # skip '*]'
                segments.append(("array", "*"))
                continue
            if pos < len(path) and path[pos] in ("'", '"'):
                q = path[pos]
                pos += 1
                start = pos
                while pos < len(path) and path[pos] != q:
                    pos += 1
                key = path[start:pos]
                pos += 2  # skip closing quote + ']'
                segments.append(("key", key))
                continue
            m = re.match(r"(\d+)", path[pos:])
            if m:
                idx = int(m.group(1))
                pos += len(m.group(1)) + 1  # skip digits + ']'
                segments.append(("array", idx))
                continue
            return False  # unrecognised bracket content
        else:
            break  # unexpected character – bail out

    return _check_json_path(data, segments)


class TestJsonPathConstrainedMixin:
    """
    Mixin that adds json_path constraint tests to a test class.

    The host test class must define ``self.base_url`` pointing at a running
    SGLang server (e.g. ``"http://localhost:30000"``).
    """

    def _run_decode_json_path(
        self,
        json_path: str,
        prompt: str,
        max_new_tokens: int = 256,
        n: int = 1,
    ):
        """
        POST a generation request with a json_path constraint and return the
        list of generated text strings.

        Args:
            json_path: The JSONPath expression to constrain the output.
            prompt: The text prompt to send to the model.
            max_new_tokens: Maximum number of tokens to generate.
            n: Number of completions to request.

        Returns:
            A list of generated text strings (one per completion).
        """
        response = requests.post(
            self.base_url + "/generate",
            json={
                "text": prompt,
                "sampling_params": {
                    "temperature": 0.0 if n == 1 else 0.5,
                    "max_new_tokens": max_new_tokens,
                    "n": n,
                    "json_path": json_path,
                },
                "stream": False,
            },
        )
        ret = response.json()
        print(json.dumps(ret, indent=2))
        print("=" * 80)

        if not isinstance(ret, list):
            self.fail(
                f"Expected response to be a list, but got {type(ret).__name__}: {ret!r}"
            )

        texts = []
        for item in ret:
            text = item.get("text", "").strip()
            if not text:
                self.fail("Generated text is empty.")
            texts.append(text)

        return texts

    # ------------------------------------------------------------------
    # Individual test cases
    # ------------------------------------------------------------------

    def test_json_path_simple_key(self):
        """Generated JSON must contain a top-level ``name`` key."""
        path = "$.name"
        prompt = (
            'Generate a JSON object with a "name" key whose value is a string. '
            "Output only the JSON, nothing else."
        )
        texts = self._run_decode_json_path(json_path=path, prompt=prompt, n=1)
        for text in texts:
            if not validate_json_path(text, path):
                self.fail(
                    f"Text does not satisfy json_path '{path}':\n{text!r}"
                )

    def test_json_path_nested_key(self):
        """Generated JSON must contain ``address.city``."""
        path = "$.address.city"
        prompt = (
            'Generate a JSON object with an "address" key whose value is '
            'an object containing a "city" key. '
            "Output only the JSON, nothing else."
        )
        texts = self._run_decode_json_path(json_path=path, prompt=prompt, n=1)
        for text in texts:
            if not validate_json_path(text, path):
                self.fail(
                    f"Text does not satisfy json_path '{path}':\n{text!r}"
                )

    def test_json_path_array_wildcard(self):
        """Generated JSON must be an array where every element has an ``id`` key."""
        path = "$[*].id"
        prompt = (
            "Generate a JSON array of objects, each with an integer "
            '"id" field. Output only the JSON array, nothing else.'
        )
        texts = self._run_decode_json_path(json_path=path, prompt=prompt, n=1)
        for text in texts:
            if not validate_json_path(text, path):
                self.fail(
                    f"Text does not satisfy json_path '{path}':\n{text!r}"
                )

    def test_json_path_deep_nested(self):
        """Generated JSON must satisfy ``$.store.book[*].author``."""
        path = "$.store.book[*].author"
        prompt = (
            'Generate a JSON object with a "store" key, inside which there is '
            'a "book" key containing an array of objects, each with an '
            '"author" key. Output only the JSON, nothing else.'
        )
        texts = self._run_decode_json_path(json_path=path, prompt=prompt, n=1)
        for text in texts:
            if not validate_json_path(text, path):
                self.fail(
                    f"Text does not satisfy json_path '{path}':\n{text!r}"
                )

    def test_json_path_bracket_notation(self):
        """Bracket-notation key access should work: ``$['user']['email']``."""
        path = "$['user']['email']"
        prompt = (
            'Generate a JSON object with a "user" key whose value is an object '
            'containing an "email" key. Output only the JSON, nothing else.'
        )
        texts = self._run_decode_json_path(json_path=path, prompt=prompt, n=1)
        for text in texts:
            if not validate_json_path(text, path):
                self.fail(
                    f"Text does not satisfy json_path '{path}':\n{text!r}"
                )

    def test_json_path_root_only(self):
        """A bare ``$`` path should accept any valid JSON object."""
        path = "$"
        prompt = "Generate a simple JSON object. Output only the JSON."
        texts = self._run_decode_json_path(json_path=path, prompt=prompt, n=1)
        for text in texts:
            # Only requirement: valid JSON
            try:
                json.loads(text)
            except (json.JSONDecodeError, ValueError):
                self.fail(f"Text is not valid JSON for path '$':\n{text!r}")

