"""
Test mixin for json_path constraint tests.

Usage::

    class TestJsonPathXGrammar(TestJsonPathConstrainedMixin, unittest.TestCase):
        base_url = "http://localhost:30000"
"""

import json
import re

import requests


def _check_json_path(data: object, segments) -> bool:
    """
    Recursively verify that *data* satisfies the structural requirements of a
    pre-parsed list of path segments.

    Each segment is a ``(type, value)`` tuple as produced by the tokeniser in
    :mod:`sglang.srt.constrained.json_path_constraint`.
    """
    if not segments:
        # All segments consumed – the path exists in *data*
        return True

    seg_type, seg_value = segments[0]
    rest = segments[1:]

    if seg_type == "key":
        if not isinstance(data, dict):
            return False
        if seg_value not in data:
            return False
        return _check_json_path(data[seg_value], rest)

    if seg_type == "array":
        if not isinstance(data, list):
            return False
        if seg_value == "*":
            # Every element must satisfy the remainder of the path
            if not data:
                return False
            return all(_check_json_path(item, rest) for item in data)
        # Integer index
        idx = int(seg_value)
        if idx >= len(data):
            return False
        return _check_json_path(data[idx], rest)

    return False


def validate_json_path(text: str, path: str) -> bool:
    """
    Return ``True`` when *text* is valid JSON and the JSON value it contains
    satisfies the structural requirements implied by *path*.

    This helper is intentionally self-contained (no dependency on the
    ``json_path_constraint`` module) so that tests can run without importing
    the server-side code.

    Args:
        text: The generated text to validate.
        path: A JSONPath expression starting with ``$``.

    Returns:
        ``True`` if the text passes validation, ``False`` otherwise.
    """
    # Must parse as valid JSON
    try:
        data = json.loads(text)
    except (json.JSONDecodeError, ValueError):
        return False

    if not path.startswith("$"):
        return False

    # Tokenise the path locally (mirrors json_path_constraint._tokenize)
    segments = []
    pos = 1  # skip '$'
    while pos < len(path):
        ch = path[pos]
        if ch == ".":
            pos += 1
            if pos < len(path) and path[pos] != "[":
                m = re.match(r"([A-Za-z_$][A-Za-z0-9_$\-]*)", path[pos:])
                if m:
                    segments.append(("key", m.group(1)))
                    pos += len(m.group(1))
                    continue
        if pos < len(path) and path[pos] == "[":
            pos += 1  # skip '['
            if pos < len(path) and path[pos] == "*":
                pos += 2  # skip '*]'
                segments.append(("array", "*"))
                continue
            if pos < len(path) and path[pos] in ("'", '"'):
                q = path[pos]
                pos += 1
                start = pos
                while pos < len(path) and path[pos] != q:
                    pos += 1
                key = path[start:pos]
                pos += 2  # skip closing quote + ']'
                segments.append(("key", key))
                continue
            m = re.match(r"(\d+)", path[pos:])
            if m:
                idx = int(m.group(1))
                pos += len(m.group(1)) + 1  # skip digits + ']'
                segments.append(("array", idx))
                continue
            return False  # unrecognised bracket content
        else:
            break  # unexpected character – bail out

    return _check_json_path(data, segments)


